  1015→// removeNullValuesRecursivelyWithContext removes null values from nested objects and arrays
  1016→// This matches the frontend's JSON.stringify/parse behavior in getSaveModelClone()
  1017→func removeNullValuesRecursivelyWithContext(data interface{}, panelType string) {
  1018→	switch v := data.(type) {
  1019→	case map[string]interface{}:
  1020→		// Remove null values from map
  1021→		for key, value := range v {
